import numpy as np

class CurriculumScheduler:
    def __init__(self, difficulty_scores: np.ndarray, start_fraction: float = 0.3, n_epochs: int = 10):
        self.n = len(difficulty_scores)
        self.start_fraction = start_fraction
        self.n_epochs = n_epochs
        self.step_size = (1.0 - start_fraction) / n_epochs
        self.sorted_indices = np.argsort(difficulty_scores)

    def get_indices(self, epoch: int) -> np.ndarray:
        fraction = min(1.0, self.start_fraction + epoch * self.step_size)
        n_include = max(1, int(fraction * self.n))
        selected = self.sorted_indices[:n_include]
        return np.sort(selected)
